 {"id":"coding_agent_session_search-513l","title":"FR-7: Attachment Support","description":"# FR-7: Attachment Support (Opt-in)

## Overview
Large assets (images, PDFs, code snapshots) that agents reference can be included in exports. This is opt-in to minimize default export size.

## CLI Interface
```
OPTIONS:
    --include-attachments       Include referenced attachments in export
    --attachment-limit <SIZE>   Max size per attachment [default: 10MB]
    --attachments-total <SIZE>  Max total attachment size [default: 100MB]
    --attachment-types <LIST>   Allowed MIME types [default: image/*,text/*,application/pdf]
```

## Storage Architecture

### Directory Structure
```
site/
├── payload/
│   └── chunk-*.bin          # Encrypted database
└── blobs/                   # Encrypted attachment blobs
    ├── sha256-abc123.bin    # Each blob named by content hash
    ├── sha256-def456.bin
    └── ...

private/
└── attachment-manifest.json  # Maps hashes to original filenames (optional)
```

### Database Schema Extension
```sql
-- Add to export schema (only when --include-attachments)
CREATE TABLE IF NOT EXISTS attachments (
    hash TEXT PRIMARY KEY,           -- SHA256 of plaintext content
    filename TEXT NOT NULL,          -- Original filename
    mime_type TEXT NOT NULL,         -- MIME type (image/png, text/plain, etc.)
    size_bytes INTEGER NOT NULL,     -- Size before encryption
    encrypted_size INTEGER,          -- Size after encryption (with overhead)
    message_id INTEGER,              -- Which message referenced this
    created_at INTEGER,
    FOREIGN KEY (message_id) REFERENCES messages(id)
);

CREATE INDEX idx_attachments_message ON attachments(message_id);

-- Messages table gets attachment_refs column
ALTER TABLE messages ADD COLUMN attachment_refs TEXT;
-- JSON array: ["sha256-abc123", "sha256-def456"]
```

## Attachment Discovery

### Finding Referenced Files
```rust
/// Scan message content for file references
fn discover_attachments(message: &NormalizedMessage, workspace: &Path) -> Vec<AttachmentRef> {
    let mut refs = Vec::new();

    // Pattern 1: Markdown image syntax ![alt](path)
    let img_regex = Regex::new(r"!\[([^\]]*)\]\(([^)]+)\)").unwrap();
    for cap in img_regex.captures_iter(&message.content) {
        let path = cap.get(2).unwrap().as_str();
        if let Some(resolved) = resolve_path(path, workspace) {
            refs.push(AttachmentRef {
                original_ref: path.to_string(),
                resolved_path: resolved,
                ref_type: RefType::MarkdownImage,
            });
        }
    }

    // Pattern 2: File paths in code blocks
    let path_regex = Regex::new(r#"(?:^|\s|["'])(/[^\s"']+\.(png|jpg|jpeg|gif|pdf|svg|txt|md))"#).unwrap();
    for cap in path_regex.captures_iter(&message.content) {
        let path = cap.get(1).unwrap().as_str();
        if let Some(resolved) = resolve_path(path, workspace) {
            refs.push(AttachmentRef {
                original_ref: path.to_string(),
                resolved_path: resolved,
                ref_type: RefType::AbsolutePath,
            });
        }
    }

    // Pattern 3: Agent-specific attachment markers
    // Claude Code: <attachment path="...">
    // Cursor: "file://..."
    // etc.

    refs
}

/// Resolve relative/absolute paths to actual files
fn resolve_path(path: &str, workspace: &Path) -> Option<PathBuf> {
    let path_buf = PathBuf::from(path);

    // Try absolute path first
    if path_buf.is_absolute() && path_buf.exists() {
        return Some(path_buf);
    }

    // Try relative to workspace
    let relative = workspace.join(&path_buf);
    if relative.exists() {
        return Some(relative);
    }

    // Try relative to message source
    // ...

    None
}
```

## Attachment Processing

### Size Validation
```rust
fn validate_attachment(
    path: &Path,
    config: &AttachmentConfig,
    running_total: &mut usize,
) -> Result<AttachmentMeta, AttachmentError> {
    let metadata = fs::metadata(path)?;
    let size = metadata.len() as usize;

    // Check per-file limit
    if size > config.max_per_file {
        return Err(AttachmentError::TooLarge {
            path: path.to_path_buf(),
            size,
            limit: config.max_per_file,
        });
    }

    // Check running total
    if *running_total + size > config.max_total {
        return Err(AttachmentError::TotalExceeded {
            current: *running_total,
            adding: size,
            limit: config.max_total,
        });
    }

    // Validate MIME type
    let mime = mime_guess::from_path(path)
        .first()
        .ok_or(AttachmentError::UnknownType(path.to_path_buf()))?;

    if !config.allowed_types.iter().any(|allowed| {
        mime.type_().as_str() == allowed.type_().as_str() &&
        (allowed.subtype() == "*" || mime.subtype() == allowed.subtype())
    }) {
        return Err(AttachmentError::TypeNotAllowed {
            path: path.to_path_buf(),
            mime: mime.to_string(),
        });
    }

    *running_total += size;

    Ok(AttachmentMeta {
        path: path.to_path_buf(),
        size,
        mime: mime.to_string(),
    })
}
```

### Content Hashing & Deduplication
```rust
fn hash_attachment(path: &Path) -> Result<String, io::Error> {
    use sha2::{Sha256, Digest};

    let mut file = File::open(path)?;
    let mut hasher = Sha256::new();
    let mut buffer = [0u8; 8192];

    loop {
        let n = file.read(&mut buffer)?;
        if n == 0 { break; }
        hasher.update(&buffer[..n]);
    }

    let hash = hasher.finalize();
    Ok(format!("sha256-{}", hex::encode(hash)))
}

/// Process and deduplicate attachments
fn process_attachments(
    refs: Vec<AttachmentRef>,
    config: &AttachmentConfig,
) -> Result<(Vec<AttachmentRecord>, HashMap<String, PathBuf>), Error> {
    let mut seen: HashMap<String, PathBuf> = HashMap::new();
    let mut records = Vec::new();
    let mut total_size = 0usize;

    for ref_ in refs {
        let hash = hash_attachment(&ref_.resolved_path)?;

        // Skip if already processed (dedup)
        if seen.contains_key(&hash) {
            continue;
        }

        let meta = validate_attachment(&ref_.resolved_path, config, &mut total_size)?;

        seen.insert(hash.clone(), ref_.resolved_path.clone());
        records.push(AttachmentRecord {
            hash: hash.clone(),
            filename: ref_.resolved_path.file_name()
                .map(|n| n.to_string_lossy().to_string())
                .unwrap_or_default(),
            mime_type: meta.mime,
            size_bytes: meta.size,
            source_path: ref_.resolved_path,
        });
    }

    Ok((records, seen))
}
```

### Encryption
```rust
/// Encrypt and write attachment blob
fn encrypt_attachment(
    record: &AttachmentRecord,
    dek: &[u8; 32],
    export_id: &[u8; 16],
    output_dir: &Path,
) -> Result<EncryptedBlob, EncryptError> {
    let plaintext = fs::read(&record.source_path)?;

    // Generate per-blob nonce
    let mut nonce = [0u8; 12];
    rand::thread_rng().fill_bytes(&mut nonce);

    // AAD includes export_id and blob hash for binding
    let aad = build_blob_aad(export_id, &record.hash);

    let cipher = Aes256Gcm::new(Key::<Aes256Gcm>::from_slice(dek));
    let ciphertext = cipher.encrypt(
        Nonce::from_slice(&nonce),
        Payload { msg: &plaintext, aad: &aad }
    )?;

    // Write to blobs/sha256-xxx.bin
    let blob_path = output_dir.join("blobs").join(format!("{}.bin", record.hash));
    fs::create_dir_all(blob_path.parent().unwrap())?;

    // Prepend nonce to ciphertext
    let mut output = Vec::with_capacity(12 + ciphertext.len());
    output.extend_from_slice(&nonce);
    output.extend_from_slice(&ciphertext);
    fs::write(&blob_path, &output)?;

    Ok(EncryptedBlob {
        hash: record.hash.clone(),
        nonce,
        encrypted_size: output.len(),
    })
}
```

## Browser-Side Loading

### Lazy Loading
```javascript
// Attachments are NOT prefetched - loaded on demand only
async function loadAttachment(hash, dek) {
    const response = await fetch(`./blobs/${hash}.bin`);
    if (!response.ok) {
        throw new Error(`Attachment ${hash} not found`);
    }

    const encrypted = new Uint8Array(await response.arrayBuffer());

    // Extract nonce (first 12 bytes)
    const nonce = encrypted.slice(0, 12);
    const ciphertext = encrypted.slice(12);

    // Build AAD
    const aad = buildBlobAad(exportId, hash);

    // Decrypt
    const dekKey = await crypto.subtle.importKey(
        'raw', dek, { name: 'AES-GCM' }, false, ['decrypt']
    );

    const plaintext = await crypto.subtle.decrypt(
        { name: 'AES-GCM', iv: nonce, additionalData: aad },
        dekKey,
        ciphertext
    );

    return new Uint8Array(plaintext);
}
```

### Preview Rendering
```javascript
async function renderAttachment(hash, mimeType, container) {
    const data = await loadAttachment(hash, sessionDek);
    const blob = new Blob([data], { type: mimeType });
    const url = URL.createObjectURL(blob);

    try {
        if (mimeType.startsWith('image/')) {
            const img = document.createElement('img');
            img.src = url;
            img.className = 'attachment-image';
            container.appendChild(img);
        } else if (mimeType === 'application/pdf') {
            const embed = document.createElement('embed');
            embed.src = url;
            embed.type = 'application/pdf';
            embed.className = 'attachment-pdf';
            container.appendChild(embed);
        } else if (mimeType.startsWith('text/')) {
            const pre = document.createElement('pre');
            pre.textContent = new TextDecoder().decode(data);
            pre.className = 'attachment-text';
            Prism.highlightElement(pre);
            container.appendChild(pre);
        } else {
            // Download button for other types
            const link = document.createElement('a');
            link.href = url;
            link.download = getFilename(hash);
            link.textContent = 'Download attachment';
            link.className = 'attachment-download';
            container.appendChild(link);
        }
    } finally {
        // Revoke after a delay to allow rendering
        setTimeout(() => URL.revokeObjectURL(url), 5000);
    }
}
```

