+                "unit-spelling equivalence violated: {:?}->{} vs {:?}->{}, \
+                 diff={}ms exceeds tolerance {tolerance_ms}ms",
+                first.0,
+                first.1,
+                other.0,
+                other.1,
+                (first.1 - other.1).abs()
+            );
+        }
+    }
+}
